              </div>
            </div>
          </div>

          {/* About Company */}
          <div className="glass-card rounded-2xl p-6">
            <h3 className="text-sm font-semibold text-white mb-4 flex items-center gap-2">
              <FileText size={16} className="text-cyan-400" />
