              </div>
              <div>
                <label className="text-xs text-gray-400 font-medium block mb-1.5">Email *</label>
                <div className="relative">
                  <Mail size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
