export function LeaderboardWidget() {
  const { getLeaderboard } = useGamification();
  const { user } = useAuth();
  const [entries, setEntries] = useState<LeaderboardEntry[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    async function loadLeaderboard() {
      setLoading(true);
      try {
        const data = await getLeaderboard(10);
        if (!cancelled) {
          setEntries(data as LeaderboardEntry[]);
        }
      } catch {
        // error already logged by hook
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    loadLeaderboard();
    return () => { cancelled = true; };
  }, [getLeaderboard]);

  const now = new Date();
  const monthYear = now.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

  if (loading) return <LeaderboardSkeleton />;

  const top3 = entries.slice(0, 3);
  const rest = entries.slice(3, 10);

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="glass-card rounded-2xl overflow-hidden"
    >
      {/* Top gradient accent */}
      <div className="h-[2px] w-full" style={{
        background: 'linear-gradient(90deg, #FFD700, #7c3aed, #06b6d4)',
      }} />

      <div className="p-5">
        {/* ── Header ── */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2.5">
            <motion.div
              animate={{ rotate: [0, -8, 8, 0] }}
              transition={{ duration: 1.5, repeat: Infinity, repeatDelay: 4 }}
            >
              <Trophy className="w-5 h-5 text-amber-400" />
            </motion.div>
            <h2 className="text-base font-bold font-[Outfit] text-white">
              Monthly Leaderboard 🏆
            </h2>
          </div>
          <span className="text-xs text-white/30 font-medium">
            {monthYear}
          </span>
        </div>

        {/* ── Top 3 Podium ── */}
        {top3.length > 0 && (
          <div className={`grid gap-3 mb-5 ${
            top3.length === 3 ? 'grid-cols-3' : top3.length === 2 ? 'grid-cols-2' : 'grid-cols-1 max-w-[200px] mx-auto'
          }`}>
            {top3.map((entry, index) => (
              <PodiumCard
                key={entry.id || entry.uid}
                entry={entry}
                rank={index + 1}
                isCurrentUser={user?.uid === entry.uid}
                index={index}
              />
            ))}
          </div>
        )}

        {/* ── Remaining list (4–10) ── */}
        {rest.length > 0 && (
          <div className="glass-card rounded-xl overflow-hidden">
            <div className="divide-y divide-white/[0.04]">
              {rest.map((entry, index) => (
                <LeaderboardRow
                  key={entry.id || entry.uid}
                  entry={entry}
                  rank={index + 4}
                  isCurrentUser={user?.uid === entry.uid}
                  index={index}
                />
              ))}
            </div>
          </div>
        )}

        {/* ── Empty state ── */}
        {entries.length === 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-center py-10"
          >
            <Trophy className="w-10 h-10 text-white/15 mx-auto mb-3" />
            <p className="text-sm text-white/40">
              No leaderboard data yet this month.
            </p>
            <p className="text-xs text-white/25 mt-1">
              Earn points to claim your spot!
            </p>
          </motion.div>
        )}
      </div>
    </motion.div>
  );
}

